    [Fact]
    public async Task Test_WsUpgradeHandshake()
    {
        // Tests WebSocket upgrade returns 101 Switching Protocols with correct Sec-WebSocket-Accept header
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/ws_upgrade_handshake");
        request.Headers.Add("Sec-WebSocket-Version", "13");
        request.Headers.Add("Sec-WebSocket-Key", "dGhlIHNhbXBsZSBub25jZQ==");
        var response = await client.SendAsync(request);
        Assert.Equal(101, (int)response.StatusCode);
        Assert.True(response.Headers.TryGetValues("Sec-WebSocket-Accept", out var hdr0) && hdr0.Any(v => v.Contains("s3pPLMBiTxaQ9kYGzzhZRbK+xOo=")), "header Sec-WebSocket-Accept mismatch");
        Assert.True(response.Headers.TryGetValues("Upgrade", out var hdr1) && hdr1.Any(v => v.Contains("websocket")), "header Upgrade mismatch");
        Assert.True(response.Headers.TryGetValues("Connection", out var hdr2) && hdr2.Any(v => v.Contains("Upgrade")), "header Connection mismatch");
    }
